firmware_template.source:
#include "ir_receiver.h"
#include <IRrecv.h>
#include <IRutils.h>
#define IR_PIN 15
static IRrecv irrecv(IR_PIN);
static decode_results results;
static uint32_t _code=0;static bool _avail=false;
void ir_rx_setup(){irrecv.enableIRIn();Serial.println("[ir_rx] OK");}
void ir_rx_loop(){if(irrecv.decode(&results)){_code=results.value;_avail=true;irrecv.resume();}}
uint32_t ir_rx_get_code(){_avail=false;return _code;}
bool ir_rx_available(){return _avail;}
